const items = $input.first().json;
const heute = new Date();

let zeilen = items.map(item => {
  const ablauf = new Date(item.Lebensende_Datum);
  const tage = Math.ceil((ablauf - heute) / (1000 * 60 * 60 * 24));
  const ablaufStr = ablauf.toLocaleDateString('de-DE');
  const warnLevel = tage <= 0 ? '🔴 UEBERFAELLIG' : tage <= 30 ? '🟠 DRINGEND' : '🟡 IN KUERZE';
  const ort = item.Kamerad ? 'Ausgegeben an: ' + item.Kamerad : 'Im Lager';
  return warnLevel + ' ' + item.Ausruestungstyp + ' (SN: ' + item.Seriennummer + ')\n  '
    + ort + ' - Lebensende: ' + ablaufStr + ' ('
    + (tage > 0 ? 'in ' + tage + ' Tagen' : Math.abs(tage) + ' Tage ueberfaellig') + ')';
}).join('\n\n');

const datum = heute.toLocaleDateString('de-DE');

return [{
  json: {
    subject: '[Ihre Feuerwehr] PSA Lebensende - ' + items.length + ' Stueck zur Aussonderung',
    html: '<h2>PSA naehert sich dem Lebensende</h2>'
      + '<p>Folgende Ausruestungsstuecke erreichen in den naechsten 6 Monaten ihr Lebensende und muessen ausgesondert werden:</p>'
      + '<pre>' + zeilen + '</pre>'
      + '<p>Bitte Ersatzbeschaffung einleiten und Ausruestung in der PSA-Verwaltung als &quot;Ausgesondert&quot; markieren.</p>'
      + '<p><b>Rechtsgrundlage:</b> §11 DGUV Vorschrift 49 - Feuerwehren</p>'
      + '<p><a href="https://IHRE-PSA-URL">PSA-Verwaltung oeffnen</a></p>'
      + '<p><small>Stand: ' + datum + ' | FF Musterort - Bekleidungsverwaltung</small></p>'
  }
}];
